import type { ColorPaletteDefinition } from '../types/color-palette.js';

/**
 * Invert the colors of a palette
 * @param colorPalette - The color palette to invert
 * @returns reversedPalette - The color palette with the reversed order
 */
export const invertColorPalette = (
  colorPalette: ColorPaletteDefinition | Record<string, string>,
) => {
  const reversedPalette: typeof colorPalette = {};

  const colors = Object.keys(colorPalette);
  const reversedColors = colors.slice().reverse();

  reversedColors.forEach((key, index) => {
    reversedPalette[key] = colorPalette[colors[colors.length - 1 - index]];
  });

  return reversedPalette;
};
